import React, { useState } from 'react';
import './EditMaterial.css';

const EditMaterial = ({ material, handleUpdate }) => {
  const [formData, setFormData] = useState({
    name: material.name,
    description: material.description,
    field: material.field,
    unitOfMeasure: material.unit_of_measure,
    extras: material.extras,
    shelfLife: material.shelflife,
    minStock: material.minstock,
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prevFormData) => ({
      ...prevFormData,
      [name]: value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    handleUpdate({ ...material, ...formData });
  };

  return (
    <div className="edit-material-container">
      <h2 className="edit-material-heading">Edit Material</h2>
      <form className="edit-material-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label htmlFor="name">Name:</label>
            <input
              type="text"
              id="name"
              name="name"
              value={formData.name}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="description">Description:</label>
            <textarea
              id="description"
              name="description"
              value={formData.description}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="field">Field:</label>
            <input
              type="text"
              id="field"
              name="field"
              value={formData.field}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="unit_of_measure">Unit of Measure:</label>
            <input
              type="text"
              id="unit_of_measure"
              name="unit_of_measure"
              value={formData.unitOfMeasure}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="extras">Extra Characteristics:</label>
            <input
              type="number"
              id="extras"
              name="extras"
              value={formData.extras}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="shelflife">Shelf Life:</label>
            <input
              type="number"
              id="shelflife"
              name="shelflife"
              value={formData.shelfLife}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="minstock">Minimum Stock:</label>
            <input
              type="number"
              id="minstock"
              name="minstock"
              value={formData.minstock}
              onChange={handleInputChange}
              required
            />
          </div>
        </div>
        <button type="submit" className="edit-material-btn">
          Add
        </button>
      </form>
    </div>
  );
};

export default EditMaterial;
